fn process_data(data: &Vec<i32>) -> (i32, i32) {
    // We need to read this vector twice, but we don't want to copy it.
    let sum1 = calculate_sum(&data);
    let sum2 = count_elements(&data);

    (sum1, sum2)
}

// Helper function 1: Calculates the total sum of the elements.
fn calculate_sum(slice: &Vec<i32>) -> i32 {
    let mut total = 0;
    for item in slice.iter() {
        total += item;
    }
    total
}

// Helper function 2: Counts how many elements there are.
fn count_elements(slice: &Vec<i32>) -> i32 {
    // Using the built-in .len() method is the most idiomatic way here.
    slice.len() as i32
}

fn main() {
    let numbers = vec![10, 20, 30, 40];
    let (sum, count) = process_data(&numbers);
    println!("The total sum is: {}", sum);
    println!("The number of elements found is: {}", count);
}

struct Book {
    title: String,
    pages: u32,
}

// This function needs to read both the title and the pages, but it shouldn't take ownership of either.
fn print_details(book: &Book) {
    println!("Title reference: {}", book.title);
    println!("Pages reference: {}", book.pages);
}

// This function needs to look at the title and the pages independently, which is tricky.
fn check_metadata(book: &Book) {
    // We cannot write this directly because Rust enforces that we can't split mutable borrows across different statements if they conflict.
    // However, since we are only reading (immutable), it works fine!
    let _title_ref = &book.title;
    let _pages_ref = &book.pages;

    println!("Successfully read title and pages separately via immutable references.");
}

fn main() {
    // Ownership is established here.
    let my_book = Book {
        title: String::from("The Rust Way"),
        pages: 350,
    };

    println!("--- Calling print_details (Immutable Borrow) ---");
    // We pass an immutable reference (&Book), which allows reading both fields.
    print_details(&my_book);

    println!("
--- Calling check_metadata (Multiple Immutable Borrows) ---");
    // This demonstrates that multiple immutable references can coexist safely.
    check_metadata(&my_book);

    // If we tried to make this mutable function, Rust would prevent us from splitting the borrow if it conflicted.
    // For example, a hypothetical function trying to mutate both title and pages simultaneously might fail compilation depending on access patterns.
}

